/**
 * A contract with no parameters.
 */
@contract def bare() = sigmaProp(HEIGHT > 1000)

/**
 * One defaulted, one not.
 * @param base base value
 * @param delta the increment
 */
@contract def mixed(base: Long, delta: Long = 5L) = sigmaProp(base + delta > 0L)

/**
 * Height-locked contract.
 * @param threshold the minimum height
 */
@contract def heightLock(threshold: Int) = sigmaProp(HEIGHT > threshold)

/**
 * Height-locked contract with a default.
 * @param threshold the minimum height
 */
@contract def heightLock(threshold: Int = 1000) = sigmaProp(HEIGHT > threshold)

/**
 * A returns tag carrying text — a reference reject.
 * @returns a sigma proposition
 */
@contract def retText(threshold: Int) = sigmaProp(HEIGHT > threshold)

/**
 * Range check on HEIGHT.
 * @param lo lower bound
 * @param hi upper bound
 */
@contract def rangeCheck(lo: Int, hi: Int) = sigmaProp(HEIGHT > lo && HEIGHT < hi)

/**
 * Combines a parameter flag with a height check.
 * @param enabled whether the lock is active
 * @param threshold the minimum height
 */
@contract def flagLock(enabled: Boolean, threshold: Int) = sigmaProp(enabled && HEIGHT > threshold)

/**
 * Range check with default bounds.
 * @param lo lower bound
 * @param hi upper bound
 */
@contract def rangeCheck(lo: Int = 100, hi: Int = 1000) = sigmaProp(HEIGHT > lo && HEIGHT < hi)
